// src/pages/ProductsPage/index.jsx (ОКОНЧАТЕЛЬНО ИСПРАВЛЕННЫЙ КОД)

import React, { useEffect, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useParams, useLocation } from 'react-router-dom';
import { 
    fetchProductsByCategory, 
    fetchAllProducts,
    fetchDiscountedProducts 
} from '../../store/slices/productsSlice'; 
import ProductCard from '../../components/ProductCard';
import FilterBar from '../../components/FilterBar';
import s from './ProductsPage.module.css';

const ProductsPage = () => {
  const dispatch = useDispatch();
  const { id } = useParams(); 
  const location = useLocation(); 

  const isSalePage = location.pathname === '/sale';

  const { 
      list: products, 
      status, 
      error,
      filters 
  } = useSelector(state => state.products);

  const categoriesList = useSelector(state => state.categories.list);

  // --- 1. ЗАГРУЗКА ДАННЫХ И ФИЛЬТРАЦИЯ (ФИНАЛЬНОЕ ИСПРАВЛЕНИЕ ЦИКЛА) ---
  useEffect(() => {
    // 🛑 Главное исправление: предотвращаем повторный диспатч, пока идет загрузка.
    if (status === 'loading') {
        return; 
    }

    // Логика выбора Thunk
    if (isSalePage) {
        // 1. Маршрут /sale
        dispatch(fetchDiscountedProducts(filters)); 
    } else if (id) {
        // 2. Маршрут /categories/:id
        // Мы передаем ID, который уже деструктурируется в слайсе.
        dispatch(fetchProductsByCategory({ id, filters })); 
    } else {
        // 3. Маршрут /products (Все товары)
        dispatch(fetchAllProducts(filters)); 
    }

    // 🛑 ИСПРАВЛЕНИЕ ЗАВИСИМОСТЕЙ: используем только примитивные значения из filters, 
    // чтобы предотвратить запуск цикла при каждом рендере, если filters - нестабильный объект.
    // Если вам нужно перезапускать fetch при смене ЛЮБОГО фильтра, 
    // вы должны передать все поля отдельно.
  }, [
      dispatch, 
      id, 
      isSalePage, 
      status, // ВАЖНО: status должен быть здесь, чтобы при успехе эффект снова проверил условие
      filters.priceFrom, 
      filters.priceTo, 
      filters.discount, 
      filters.sortBy
  ]); 

  // --- 2. ОПРЕДЕЛЕНИЕ ЗАГОЛОВКА ---
  const pageTitle = useMemo(() => {
    if (isSalePage) {
        return 'Акционные товары';
    }
    if (id) {
        const currentCategory = categoriesList.find(cat => cat.id === +id);
        return currentCategory ? currentCategory.title : 'Товары категории';
    }
    return 'Все товары';
  }, [id, categoriesList, isSalePage]);

  // --- 3. РЕНДЕРИНГ СОСТОЯНИЙ (Loading/Error) ---
  if (status === 'loading') {
    return <div className={s.container}>Загрузка товаров...</div>;
  }

  if (status === 'failed') {
    return <div className={s.container}>Ошибка при загрузке: {error}</div>;
  }

  if (products.length === 0 && status === 'succeeded') {
      const isFiltered = filters.priceFrom || filters.priceTo || filters.discount !== false || filters.sortBy !== 'default';

      return (
          <div className={s.container}>
              <h1>{pageTitle}</h1>
              <FilterBar />
              <p className={s.emptyMessage}>
                  {isFiltered 
                   ? 'Нет товаров, соответствующих текущим фильтрам.' 
                   : 'Товары не найдены.'}
              </p>
          </div>
      );
  }

  // --- 4. ОСНОВНОЙ РЕНДЕРИНГ ---
  return (
    <div className={s.container}>
      <h1>{pageTitle}</h1>

      <FilterBar /> 

      <div className={s.list}>
        {products.map(product => (
          <ProductCard 
            key={product.id}
            id={product.id}
            title={product.title}
            price={product.price}
            discont_price={product.discont_price}
            image={product.image}
          />
        ))}
      </div>
    </div>
  );
};

export default ProductsPage;
